  ('aboriginal-6f0ba476-moex-00331', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設T為稅額、t為邊際稅率、Y為所得、E為免稅額，線性累進所得稅可表示為T=t×（Y－E）， 其中當Y>E時，T>0；Y<E時，T=0。有關稅制的累進程度，下列何者正確？', '["降低邊際稅率及降低免稅額會降低稅制的累進程度", "降低邊際稅率及提高免稅額會提高稅制的累進程度", "提高邊際稅率及降低免稅額會提高稅制的累進程度", "提高邊際稅率及提高免稅額會降低稅制的累進程度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00332', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '若國營事業只有甲、乙二家企業，經營整體維持收支平衡。若甲之A商品的價格需求彈性較乙之 B商品的彈性為大，依據最適定價法則，分別訂定A、B的單價，以致A減少購買的比例較B減 少之比例為：', '["大", "相同", "小", "無法比較"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
